FROM genomic_datasets
WHERE aorta_endothel = (SELECT MAX(aorta_endothel) FROM genomic_datasets);

SELECT COUNT(tissue_name) 
FROM tissue_types
WHERE cell_type = 'epithelial';

external_knowledge:
- 'Fat cell activity' refers to the expression level of adipocytes; 
- 'Body fat' is another term for 'adipose tissue'; 
- 'Recently studied dataset' refers to a dataset accessed within the last 3 months.

sql:
SELECT DISTINCT T2.tissue_name 
FROM expression_levels AS T1 
JOIN tissue_types AS T2 ON T2.tissue_id = T1.tissue_id;
